  1025: { title: 'Forward Contract Value', note: 'Forward value', meaning: 'This gives the theoretical value of a forward contract at time t.' },
  1026: { title: 'Call Option Payoff', note: 'Call payoff', meaning: 'This is the actual payoff of a call option at maturity.' },
  1027: { title: 'Put Option Payoff', note: 'Put payoff', meaning: 'This is the actual payoff of a put option at maturity.' },
  1028: { title: 'Put-Call Parity', note: 'Put-call parity', meaning: 'This is the key no-arbitrage relation between European call and put options.' },
  1029: { title: 'Black-Scholes Call', note: 'Black-Scholes', meaning: 'This is the Black-Scholes pricing formula for a European call option.' },
  1030: { title: 'Black-Scholes Put', note: 'Black-Scholes', meaning: 'This is the Black-Scholes pricing formula for a European put option.' },
