  1034: { title: 'Gamma', note: 'Greek', meaning: 'This is the second-order sensitivity describing how fast delta changes.' },
  1035: { title: 'Theta', note: 'Greek', meaning: 'This measures how option value changes as time passes.' },
  1036: { title: 'Vega', note: 'Greek', meaning: 'This is the sensitivity of option value to changes in volatility.' },
  1037: { title: 'Rho', note: 'Greek', meaning: 'This is the sensitivity of option value to interest-rate changes.' },
  1038: { title: 'Stochastic Process', note: 'Geometric Brownian motion', meaning: 'This is the continuous-time model assuming stock prices follow geometric Brownian motion.' },
  1039: { title: 'Wiener Process', note: 'Brownian motion', meaning: 'This is Brownian motion, the basic building block of continuous-time stochastic models.' },
  1040: { title: 'Ito’s Lemma', note: 'Ito lemma', meaning: 'This is the key theorem for computing how a function changes along a stochastic differential equation.' },
  1041: { title: 'Risk-Neutral Expectation', note: 'Risk-neutral pricing', meaning: 'This prices an asset using the discounted expectation under the risk-neutral measure.' },
