  1048: { title: 'Expected Loss', note: 'Credit risk', meaning: 'This is the standard formula for expected loss in credit risk.' },
  1049: { title: 'VaR', note: 'Value at Risk', meaning: 'This is a risk measure defined by the probability that loss exceeds a specified level.' },
  1050: { title: 'Financial Mathematics Review', note: 'Review', meaning: 'This is the risk-neutral expectation formula, the central idea behind derivative pricing.' },

  1101: { title: 'Chain Complex', note: 'chain complex', meaning: 'This is the basic form of a chain complex, where boundary maps connect adjacent chain groups.' },
  1102: { title: 'Boundary Squared Zero', note: 'boundary squared zero', meaning: 'This is the core property that the composition of two consecutive boundary maps is always zero.' },
  1103: { title: 'n-Cycles', note: 'cycles', meaning: 'These are the n-chains whose boundary is zero.' },
  1104: { title: 'n-Boundaries', note: 'boundaries', meaning: 'These are the n-chains that come from the boundary of an (n+1)-chain.' },
  1105: { title: 'Homology Group', note: 'homology group', meaning: 'This defines homology as cycles modulo boundaries.' },
  1106: { title: 'Homology of a Space', note: 'singular homology', meaning: 'This is the usual definition of the nth homology group of a space X.' },
  1107: { title: 'Reduced Homology', note: 'reduced homology', meaning: 'This is reduced homology, which slightly adjusts degree 0 information.' },
  1108: { title: 'Relative Chain Group', note: 'relative chains', meaning: 'This is the definition of the relative chain group obtained by quotienting out chains in A.' },
  1109: { title: 'Relative Homology', note: 'relative homology', meaning: 'This denotes the relative homology group of the pair (X,A).' },
  1110: { title: 'Short Exact Sequence', note: 'short exact sequence', meaning: 'This is the standard basic form of a short exact sequence.' },
  1111: { title: 'Exactness 1', note: 'exactness', meaning: 'This expresses exactness at the middle term: the image of one map equals the kernel of the next.' },
  1112: { title: 'Chain Map', note: 'chain map component', meaning: 'This is the degree-n component of a map between chain complexes.' },
  1113: { title: 'Chain Map Condition', note: 'chain map', meaning: 'This says a chain map must commute with the boundary operators.' },
  1114: { title: 'Induced Map', note: 'induced map', meaning: 'A chain map induces a map on homology.' },
  1115: { title: 'Connecting Homomorphism', note: 'connecting homomorphism', meaning: 'This is the connecting map used to form a long exact sequence from a short exact sequence.' },
  1116: { title: 'Long Exact Sequence 1', note: 'long exact sequence', meaning: 'This is the standard long exact sequence in relative homology.' },
  1117: { title: 'Inclusion-Induced Map', note: 'inclusion-induced map', meaning: 'An inclusion map naturally induces a map on homology.' },
  1118: { title: 'Quotient-Induced Map', note: 'quotient-induced map', meaning: 'This is the map from absolute homology to relative homology induced by quotienting.' },
  1119: { title: 'Exactness 2', note: 'exactness', meaning: 'This restates exactness in a long exact sequence.' },
  1120: { title: 'Zeroth Homology', note: 'connected components', meaning: 'This homology group records connected component information.' },
  1121: { title: 'Homology of a Point', note: 'point', meaning: 'A point has trivial homology in every positive degree.' },
  1122: { title: 'Zeroth Homology of a Point', note: 'point', meaning: 'The degree-0 homology of a point is isomorphic to the integers.' },
  1123: { title: 'First Homology of the Circle', note: 'circle', meaning: 'The circle has one 1-dimensional hole, so its first homology is the integers.' },
  1124: { title: 'Zeroth Homology of the Circle', note: 'circle', meaning: 'Since the circle is connected, its zeroth homology is the integers.' },
  1125: { title: 'Top Homology of the Sphere', note: 'sphere top homology', meaning: 'The top-degree homology of S^n is isomorphic to the integers.' },
  1126: { title: 'Middle Homology of the Sphere', note: 'sphere vanishing', meaning: 'The intermediate homology groups of a sphere vanish.' },
  1127: { title: 'Reduced Homology of a Point', note: 'reduced homology', meaning: 'The reduced homology of a point is zero in every degree.' },
  1128: { title: 'Chain Homotopy', note: 'chain homotopy', meaning: 'This is the defining relation for a chain homotopy between two chain maps.' },
  1129: { title: 'Homotopy Invariance', note: 'homotopy invariance', meaning: 'Homotopic maps induce the same maps on homology.' },
  1130: { title: 'Excision', note: 'excision', meaning: 'This says removing a suitable subset does not change relative homology.' },
  1131: { title: 'Mayer-Vietoris', note: 'Mayer-Vietoris', meaning: 'This is the long exact sequence used to compute homology from an open cover decomposition.' },
  1132: { title: 'Naturality', note: 'naturality', meaning: 'This expresses that connecting maps commute naturally with induced maps.' },
  1133: { title: 'Free Abelian Group of Chains', note: 'singular chains', meaning: 'The singular chain group is a free abelian group generated by singular simplices.' },
  1134: { title: 'Singular Simplex', note: 'singular simplex', meaning: 'A singular simplex is a continuous map from the standard simplex into the space X.' },
  1135: { title: 'Boundary Formula', note: 'boundary formula', meaning: 'The boundary of a simplex is given by the alternating sum of its faces.' },
  1136: { title: 'Cochain Group', note: 'cochains', meaning: 'The cochain group consists of homomorphisms from chains into the coefficient group G.' },
  1137: { title: 'Coboundary', note: 'coboundary', meaning: 'This is the map that raises degree by one in a cochain complex.' },
  1138: { title: 'Cohomology Group', note: 'cohomology', meaning: 'Cohomology is defined as cocycles modulo coboundaries.' },
