  1149: { title: 'Euler Characteristic', note: 'Euler characteristic', meaning: 'This computes the Euler characteristic as the alternating sum of homology ranks.' },
  1150: { title: 'Homological Algebra Review', note: 'review', meaning: 'This is the most central defining formula for homology in homological algebra and algebraic topology.' },

